  type: 'CustomNode',
  execute: async (input: any) => {
    try {
      const parsed = await parser.parse(input.content);
      return { ...input, validated: true, data: parsed };
    } catch (e) {
      return { ...input, validated: false, error: e.message };
    }
  }
};

