class PersistentContextAggregator {
  private sessionStore = new Map<string, any[]>();

  aggregate(sessionId: string, newContext: any) {
    if (!this.sessionStore.has(sessionId)) {
      this.sessionStore.set(sessionId, []);
    }
    const context = this.sessionStore.get(sessionId);
    context.push(newContext);

    // Limit context window
    if (context.length > 10) {
      context.shift();
    }

    return context;
  }
}

const aggregatorNode = new PersistentContextAggregator();

